mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM agent_cache_repair_task
    WHERE task_id = #{taskId}
)

SELECT EXISTS (
    SELECT 1
    FROM agent_cache_repair_task
    WHERE task_id = #{taskId}
      AND status = 'PENDING'
)

SELECT *
FROM agent_cache_repair_task
WHERE status = 'PENDING'
  AND next_attempt_at <= #{now}
ORDER BY next_attempt_at ASC, task_id ASC
LIMIT #{limit}
